const { Buffer } = require("node:buffer");

const utf8Buf = Buffer.from("hello", "utf8");
const hexBuf = Buffer.from("68656c6c6f", "hex");
const base64Buf = Buffer.from("aGVsbG8=", "base64");
const concat = Buffer.concat([Buffer.from("abc", "utf8"), Buffer.from("def", "utf8")]);

module.exports = {
    utf8: utf8Buf.toString("utf8"),
    byteLen: Buffer.byteLength("hello", "utf8"),
    hex: hexBuf.toString("hex"),
    base64: base64Buf.toString("base64"),
    concat: concat.toString("utf8"),
};
